"use strict";(self.webpackChunkdst_api_webdocs=self.webpackChunkdst_api_webdocs||[]).push([[560267],{496292:e=>{e.exports=JSON.parse('{"tag":{"label":"season","permalink":"/dst-api-webdocs/docs/tags/season","allTagsPath":"/dst-api-webdocs/docs/tags","count":16,"items":[{"id":"game-scripts/prefabs/ancienttrees","title":"Ancienttrees","description":"Manages the lifecycle, growth, and interaction of ancient trees and their saplings, including seed deployment, growth staging, fruit production, and stump conversion upon harvesting.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/ancienttrees"},{"id":"game-scripts/brains/beargerbrain","title":"Beargerbrain","description":"Controls the behavior tree and AI logic for the Bearger boss, managing combat, foraging, and seasonal movement patterns.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/beargerbrain"},{"id":"game-scripts/prefabs/beefaloherd","title":"Beefaloherd","description":"Manages beefalo herd behavior, mating seasons, and baby beefalo spawning.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/beefaloherd"},{"id":"game-scripts/scenarios/chest_winter","title":"Chest Winter","description":"Defines the behavior and loot distribution for a winter-themed chest that triggers seasonal changes when opened.","permalink":"/dst-api-webdocs/docs/game-scripts/scenarios/chest_winter"},{"id":"game-scripts/map/forest_map","title":"Forest Map","description":"Handles procedural generation of the Forest biome\'s terrain, topology, entities, roads, and seasonal/weather configuration for Don\'t Starve Together world generation.","permalink":"/dst-api-webdocs/docs/game-scripts/map/forest_map"},{"id":"game-scripts/scenarios/icebox_summer","title":"Icebox Summer","description":"Handles seasonal trap logic and loot setup for a special ice-themed chest that triggers summer season upon opening.","permalink":"/dst-api-webdocs/docs/game-scripts/scenarios/icebox_summer"},{"id":"game-scripts/prefabs/koalefant","title":"Koalefant","description":"Creates the Koalefant entity (a seasonal large herbivore) with combat, movement, sleeping behavior, poop spawing, and seasonally variant loot.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/koalefant"},{"id":"game-scripts/components/mood","title":"Mood","description":"Manages timed and seasonal mood states for entities, such as mating behavior in beefalo, by tracking mood duration, season-based activation, and world settings multipliers.","permalink":"/dst-api-webdocs/docs/game-scripts/components/mood"},{"id":"game-scripts/prefabs/mushtree","title":"Mushtree","description":"Manages lifecycle, growth, seasonal changes, acid rain effects, and loot generation for mushtree entities in the Cave biome.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/mushtree"},{"id":"game-scripts/components/penguinspawner","title":"Penguinspawner","description":"Manages penguin flock spawning, colony formation, and seasonal population control in winter.","permalink":"/dst-api-webdocs/docs/game-scripts/components/penguinspawner"},{"id":"game-scripts/components/regrowthmanager","title":"Regrowthmanager","description":"Manages the scheduled regrowth of harvestable plants and structures after they are collected, using time-based timers and world state conditions.","permalink":"/dst-api-webdocs/docs/game-scripts/components/regrowthmanager"},{"id":"game-scripts/prefabs/rockyherd","title":"Rockyherd","description":"Manages the herd system for spawning and maintaining groups of Rocky entities in the world, including seasonal spawning behavior and member population limits.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/rockyherd"},{"id":"game-scripts/components/shard_seasons","title":"Shard Seasons","description":"Manages season state synchronization between master shard and clients for a specific shard entity in Don\'t Starve Together.","permalink":"/dst-api-webdocs/docs/game-scripts/components/shard_seasons"},{"id":"game-scripts/prefabs/sharkboi_ice_hazard","title":"Sharkboi Ice Hazard","description":"Manages a dynamic, seasonally-adjusted ice boulder that melts or grows over time and can be mined for ice shards.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/sharkboi_ice_hazard"},{"id":"game-scripts/components/spooked","title":"Spooked","description":"Manages seasonal spook level accumulation and triggers spook events (e.g., tree-specific FX) when spook level exceeds a threshold.","permalink":"/dst-api-webdocs/docs/game-scripts/components/spooked"},{"id":"game-scripts/components/worldstate","title":"Worldstate","description":"Tracks and broadcasts global world state variables such as time, phase, season, weather, and moon cycles for the entire world entity.","permalink":"/dst-api-webdocs/docs/game-scripts/components/worldstate"}],"unlisted":false}}')}}]);